def safe_json_deserialize(raw_bytes: bytes) -> dict:
    """
    Safely deserialize JSON from bytes.
    
    SECURITY: We use json.loads() which is safe against code injection,
    unlike pickle.loads() or yaml.load() which can execute arbitrary code.
    Never use pickle, eval, exec, or yaml.unsafe_load for deserialization
    of untrusted data.
    """
    if not isinstance(raw_bytes, (bytes, bytearray)):
        raise ValidationError("Message must be bytes")

    if len(raw_bytes) > MAX_MESSAGE_SIZE:
        raise ValidationError(
            f"Message size {len(raw_bytes)} exceeds maximum {MAX_MESSAGE_SIZE}"
        )

    if len(raw_bytes) == 0:
        raise ValidationError("Empty message received")

    try:
        # json.loads is safe - it only parses JSON data structures
        # and cannot execute arbitrary code
        data = json.loads(raw_bytes.decode('utf-8'))
    except (json.JSONDecodeError, UnicodeDecodeError) as e:
        raise ValidationError(f"Invalid JSON: {e}")

    if not isinstance(data, dict):
        raise ValidationError("Message must be a JSON object")

    # Limit nesting depth to prevent DoS via deeply nested structures
    _check_nesting_depth(data, max_depth=5)

    return data


def _check_nesting_depth(obj, max_depth: int, current_depth: int = 0):
    """Prevent deeply nested JSON structures that could cause stack overflow."""
    if current_depth > max_depth:
        raise ValidationError(
            f"JSON nesting depth exceeds maximum of {max_depth}"
        )
    if isinstance(obj, dict):
        for value in obj.values():
            _check_nesting_depth(value, max_depth, current_depth + 1)
    elif isinstance(obj, list):
        if len(obj) > 1000:
            raise ValidationError("Array too large in message")
        for item in obj:
            _check_nesting_depth(item, max_depth, current_depth + 1)


def validate_and_parse_transaction(data: dict) -> TransactionMessage:
    """
    Validate all fields of a transaction message with strict rules.
    Returns an immutable TransactionMessage on success.
    """
    # Check required fields exist
    required_fields = {
        'transaction_id', 'transaction_type', 'amount',
        'currency', 'source_account', 'timestamp'
    }
    missing = required_fields - set(data.keys())
    if missing:
        raise ValidationError(f"Missing required fields: {missing}")

    # Validate transaction_id (UUID format)
    transaction_id = data['transaction_id']
    if not isinstance(transaction_id, str):
        raise ValidationError("transaction_id must be a string")
    if not TRANSACTION_ID_PATTERN.match(transaction_id):
        raise ValidationError(
            f"Invalid transaction_id format: {transaction_id!r}"
        )

    # Validate transaction_type against whitelist
    transaction_type = data['transaction_type']
    if not isinstance(transaction_type, str):
        raise ValidationError("transaction_type must be a string")
    transaction_type = transaction_type.lower().strip()
    if transaction_type not in ALLOWED_TRANSACTION_TYPES:
        raise ValidationError(
            f"Invalid transaction_type: {transaction_type!r}. "
            f"Allowed: {ALLOWED_TRANSACTION_TYPES}"
        )

    # Validate amount using Decimal for precision
    raw_amount = data['amount']
    if isinstance(raw_amount, bool):
        raise ValidationError("amount must be a number, not boolean")
    if not isinstance(raw_amount, (int, float, str)):
        raise ValidationError(f"Invalid amount type: {type(raw_amount)}")
    try:
        amount = Decimal(str(raw_amount))
    except (InvalidOperation, ValueError):
        raise ValidationError(f"Invalid amount value: {raw_amount!r}")

    if amount < MIN_TRANSACTION_AMOUNT:
        raise ValidationError(
            f"Amount {amount} below minimum {MIN_TRANSACTION_AMOUNT}"
        )
    if amount > MAX_TRANSACTION_AMOUNT:
        raise ValidationError(
            f"Amount {amount} exceeds maximum {MAX_TRANSACTION_AMOUNT}"
        )
    # Check for reasonable decimal places
    if abs(amount.as_tuple().exponent) > 4:
        raise ValidationError("Amount has too many decimal places")

    # Validate currency against whitelist
    currency = data['currency']
    if not isinstance(currency, str):
        raise ValidationError("currency must be a string")
    currency = currency.upper().strip()
    if currency not in ALLOWED_CURRENCIES:
        raise ValidationError(
            f"Invalid currency: {currency!r}. Allowed: {ALLOWED_CURRENCIES}"
        )

    # Validate source_account
    source_account = data['source_account']
    if not isinstance(source_account, str):
        raise ValidationError("source_account must be a string")
    if not ACCOUNT_ID_PATTERN.match(source_account):
        raise ValidationError(
            f"Invalid source_account format: {source_account!r}"
        )

    # Validate destination_account (optional for some transaction types)
    destination_account = data.get('destination_account', '')
    if destination_account:
        if not isinstance(destination_account, str):
            raise ValidationError("destination_account must be a string")
        if not ACCOUNT_ID_PATTERN.match(destination_account):
            raise ValidationError(
                f"Invalid destination_account format: {destination_account!r}"
            )
    else:
        if transaction_type == 'transfer':
            raise ValidationError(
                "destination_account required for transfer transactions"
            )
        destination_account = ''

    # Validate timestamp
    timestamp_str = data['timestamp']
    if not isinstance(timestamp_str, str):
        raise ValidationError("timestamp must be a string")
    try:
        parsed_ts = datetime.fromisoformat(
            timestamp_str.replace('Z', '+00:00')
        )
        # Reject timestamps too far in the future or past
        now = datetime.now(timezone.utc)
        diff = abs((now - parsed_ts).total_seconds())
        if diff > 86400:  # 24 hours
            raise ValidationError(
                f"Timestamp {timestamp_str} is too far from current time"
            )
    except (ValueError, TypeError):
        raise ValidationError(f"Invalid timestamp format: {timestamp_str!r}")

    # Validate optional description
    description = data.get('description', '')
    if description:
        if not isinstance(description, str):
            raise ValidationError("description must be a string")
        if not DESCRIPTION_PATTERN.match(description):
            raise ValidationError(
                "description contains invalid characters or is too long"
            )

    # Validate optional metadata (limited, sanitized)
    metadata = data.get('metadata', {})
    if not isinstance(metadata, dict):
        raise ValidationError("metadata must be a JSON object")
    if len(metadata) > 20:
        raise ValidationError("metadata has too many keys")
    sanitized_metadata = {}
    for key, value in metadata.items():
        if not isinstance(key, str) or len(key) > 64:
            raise ValidationError(f"Invalid metadata key: {key!r}")
        if not re.match(r'^[a-zA-Z0-9_\-\.]+$', key):
            raise ValidationError(
                f"Metadata key contains invalid characters: {key!r}"
            )
        if isinstance(value, str):
            if len(value) > 256:
                raise ValidationError(
                    f"Metadata value too long for key {key!r}"
                )
            sanitized_metadata[key] = value
        elif isinstance(value, (int, float)) and not isinstance(value, bool):
            sanitized_metadata[key] = value
        elif isinstance(value, bool):
            sanitized_metadata[key] = value
        else:
            raise ValidationError(
                f"Metadata value for key {key!r} must be string, number, or boolean"
            )

    return TransactionMessage(
        transaction_id=transaction_id,
        transaction_type=transaction_type,
        amount=amount,
        currency=currency,
        source_account=source_account,
        destination_account=destination_account,
        timestamp=timestamp_str,
        description=description,
        metadata=sanitized_metadata,
    )


