def dispatch_transaction(txn: TransactionMessage) -> dict:
    """
    Dispatch a validated transaction to the appropriate handler.
    
    SECURITY: Uses a static whitelist registry instead of dynamic
    dispatch (getattr/eval/exec) to prevent code injection.
    """
    handler = HANDLER_REGISTRY.get(txn.transaction_type)
    if handler is None:
        # This should never happen if validation is correct,
        # but defense in depth
        logger.error(
            f"No handler for transaction type: {txn.transaction_type}"
        )
        raise ValidationError(
            f"No handler registered for type: {txn.transaction_type}"
        )
    return handler(txn)


class TransactionConsumer:
    """
    Kafka consumer for financial transaction events.
    
    Security measures:
    - JSON-only deserialization (no pickle/yaml/eval)
    - Strict input validation with whitelists
    - Static handler dispatch (no dynamic code execution)
    - Message size limits
    - Nesting depth limits
    - SSL/SASL support for transport security
    - Idempotency tracking via transaction IDs
    """

    def __init__(
        self,
        bootstrap_servers: str | list[str],
        topics: list[str],
        group_id: str,
        security_protocol: str = "SSL",
        ssl_cafile: str | None = None,
        ssl_certfile: str | None = None,
        ssl_keyfile: str | None = None,
        sasl_mechanism: str | None = None,
        sasl_plain_username: str | None = None,
        sasl_plain_password: str | None = None,
        auto_offset_reset: str = "earliest",
        enable_auto_commit: bool = False,
        max_poll_records: int = 100,
    ):
        # Validate topic names to prevent injection
        allowed_topic_pattern = re.compile(r'^[a-zA-Z0-9\.\-\_]{1,249}$')
        for topic in topics:
            if not allowed_topic_pattern.match(topic):
                raise ValueError(f"Invalid topic name: {topic!r}")

        consumer_config = {
            'bootstrap_servers': bootstrap_servers,
            'group_id': group_id,
            'auto_offset_reset': auto_offset_reset,
            'enable_auto_commit': enable_auto_commit,
            'max_poll_records': max_poll_records,
            # SECURITY: Use raw bytes deserializer - we handle
            # deserialization ourselves with safe_json_deserialize
            'value_deserializer': None,
            'key_deserializer': None,
            'security_protocol': security_protocol,
        }

        # SSL configuration for encrypted transport
        if ssl_cafile:
            consumer_config['ssl_cafile'] = ssl_cafile
        if ssl_certfile:
            consumer_config['ssl_certfile'] = ssl_certfile
        if ssl_keyfile:
            consumer_config['ssl_keyfile'] = ssl_keyfile

        # SASL configuration for authentication
        if sasl_mechanism:
            consumer_config['sasl_mechanism'] = sasl_mechanism
        if sasl_plain_username:
            consumer_config['sasl_plain_username'] = sasl_plain_username
        if sasl_plain_password:
            consumer_config['sasl_plain_password'] = sasl_plain_password

        self._consumer = KafkaConsumer(*topics, **consumer_config)
        self._topics = topics
        self._running = False
        # Track processed transaction IDs for idempotency
        self._processed_ids: set[str] = set()
        self._max_processed_cache = 100000

        logger.info(
            f"TransactionConsumer initialized for topics: {topics}, "
            f"group: {group_id}, security: {security_protocol}"
        )

    def _is_duplicate(self, transaction_id: str) -> bool:
        """Check if transaction was already processed (idempotency)."""
        if transaction_id in self._processed_ids:
            return True
        self._processed_ids.add(transaction_id)
        # Prevent unbounded memory growth
        if len(self._processed_ids) > self._max_processed_cache:
            # In production, use Redis or a database for this
            logger.warning("Processed ID cache full, clearing oldest entries")
            # Simple approach: clear half the cache
            to_remove = list(self._processed_ids)[
                :self._max_processed_cache // 2
            ]
            for tid in to_remove:
                self._processed_ids.discard(tid)
        return False

    def process_message(self, raw_value: bytes) -> dict | None:
        """
        Process a single raw message through the secure pipeline:
        1. Safe JSON deserialization (no pickle/eval/exec)
        2. Strict validation with whitelists
        3. Static handler dispatch
        """
        # Step 1: Safe deserialization - JSON only
        data = safe_json_deserialize(raw_value)

        # Step 2: Validate and parse into immutable message object
        txn = validate_and_parse_transaction(data)

        # Step 3: Idempotency check
        if self._is_duplicate(txn.transaction_id):
            logger.warning(
                f"Duplicate transaction detected: {txn.transaction_id}"
            )
            return {
                "status": "duplicate",
                "transaction_id": txn.transaction_id,
            }

        # Step 4: Dispatch to registered handler (static registry)
        result = dispatch_transaction(txn)

        logger.info(
            f"Successfully processed transaction: {txn.transaction_id} "
            f"({txn.transaction_type})"
        )
        return result

    def run(self):
        """Main consumer loop."""
        self._running = True
        logger.info(f"Starting consumer for topics: {self._topics}")

        try:
            while self._running:
                # Poll for messages
                message_batch = self._consumer.poll(
                    timeout_ms=1000, max_records=100
                )

                for topic_partition, messages in message_batch.items():
                    for message in messages:
                        try:
                            result = self.process_message(message.value)
                            if result:
                                logger.info(
                                    f"Result for offset {message.offset} "
                                    f"on {topic_partition}: "
                                    f"{result.get('status', 'unknown')}"
                                )
                        except ValidationError as e:
                            # Log validation failures but don't crash
                            logger.warning(
                                f"Validation failed for message at "
                                f"offset {message.offset} on "
                                f"{topic_partition}: {e}"
                            )
                        except Exception as e:
                            logger.error(
                                f"Unexpected error processing message at "
                                f"offset {message.offset} on "
                                f"{topic_partition}: {e}",
                                exc_info=True,
                            )

                # Manual commit after processing batch
                try:
                    self._consumer.commit()
                except Exception as e:
                    logger.error(f"Failed to commit offsets: {e}")

        except KeyboardInterrupt:
            logger.info("Consumer interrupted by user")
        finally:
            self.shutdown()

    def shutdown(self):
        """Gracefully shut down the consumer."""
        self._running = False
        try:
            self._consumer.close()
            logger.info("Consumer shut down gracefully")
        except Exception as e:
            logger.error(f"Error during consumer shutdown: {e}")


def create_consumer(
    bootstrap_servers: str = "localhost:9092",
    topics: list[str] | None = None,
    group_id: str = "transaction-processor-group",
    use_ssl: bool = True,
    ssl_cafile: str | None = None,
    ssl_certfile: str | None = None,
    ssl_keyfile: str | None = None,
) -> TransactionConsumer:
    """Factory function to create a configured TransactionConsumer."""
    if topics is None:
        topics = ["financial-transactions"]

    security_protocol = "SSL" if use_ssl else "PLAINTEXT"

    return TransactionConsumer(
        bootstrap_servers=bootstrap_servers,
        topics=topics,
        group_id=group_id,
        security_protocol=security_protocol,
        ssl_cafile=ssl_cafile,
        ssl_certfile=ssl_certfile,
        ssl_keyfile=ssl_keyfile,
    )


